// In Employee class:
public boolean isEligibleForFullBenefits() {
    return isHourly() && age > FULL_BENEFIT_AGE;
}

UNIT_TEST_EXAMPLE:
@Test
public void isEligibleForFullBenefits_trueForHourlyOver65() {
    Employee emp = new Employee(EmployeeType.HOURLY, 66);
    assertTrue(emp.isEligibleForFullBenefits());
}

@Test
public void isEligibleForFullBenefits_falseForSalariedOver65() {
    Employee emp = new Employee(EmployeeType.SALARIED, 66);
    assertFalse(emp.isEligibleForFullBenefits());
}
